mapper.insert:
		INSERT INTO STOUNWRQ (
			   GATE_CD
             , BUYER_CD
             , DEPT_CD
             , ITEM_REQ_NO
             , ITEM_REQ_SEQ
             , REG_DATE
             , REG_USER_ID
             , MOD_DATE
             , MOD_USER_ID
             , DEL_FLAG
             , PROGRESS_CD
             , ITEM_DESC
             , ITEM_SPEC
             , MAKER_NM
             , MODEL_NM
             , BRAND_NM
             , ORIGIN_NM
             , PIC_USER_INFO
             , PIC_USER_TEL_NUM
             , UNIT_CD
             , ITEM_REQ_RMK
             , IMG_UUID
             , ATTACH_FILE_NO
             , ITEM_CTRL_USER_ID
             , ITEM_REG_DATE
		) VALUES (
               #{ses.gateCd}
             , #{ses.companyCd}
             , #{ses.deptCd}
             , #{ITEM_REQ_NO}
             , (SELECT (MAX(ITEM_REQ_SEQ),0) + 1
             	  FROM STOUNWRQ
             	 WHERE GATE_CD = #{ses.gateCd}
             	   AND BUYER_CD = #{ses.companyCd}
             	   AND DEPT_CD = #{ses.deptCd}
             	   AND ITEM_REQ_NO = #{ITEM_REQ_NO})
             , SYSDATE
             , #{ses.userId}
             , SYSDATE
             , #{ses.userId}
             , '0'
             , #{PROGRESS_CD}
             , #{ITEM_DESC}
             , #{ITEM_SPEC}
             , #{MAKER_NM}
             , #{MODEL_NM}
             , #{BRAND_NM}
             , #{ORIGIN_NM}
             , #{PIC_USER_INFO}
             , #{PIC_USER_TEL_NUM}
             , #{UNIT_CD}
             , #{ITEM_REQ_RMK}
             , #{IMG_UUID}
             , #{ATTACH_FILE_NO}
             , #{ses.userId}
             , SYSDATE
		)

