    , UNIT_CD = #{UNIT_CD}
    , DIRECT_PO_FLAG = #{DIRECT_PO_FLAG}
    , BRAND_CD = #{BRAND_CD}
    , ITEM_RMK = #{ITEM_RMK}
    , ATT_FILE_NUM = #{ATT_FILE_NUM}
    , MAJOR_ITEM_FLAG = #{MAJOR_ITEM_FLAG}
 WHERE GATE_CD  = #{ses.gateCd}
