DELETE FROM STOCMTIM
 WHERE GATE_CD = #{ses.gateCd}
  AND BUYER_CD = #{ses.companyCd}
  AND ITEM_CD  = #{ITEM_CD}
  AND UUID     = #{IMG_ATT_FILE_NUM}
  AND DEL_FLAG = '0'

mapper.update:
MERGE  STOCMTGC MTGC
USING (SELECT #{ses.gateCd}  AS GATE_CD
             ,#{ses.companyCd} AS BUYER_CD
             ,#{ITEM_CD} AS ITEM_CD
             ,(CASE WHEN SF_SUBSTR(#{ITEM_CLS1},1,1) = 'P' THEN '0' ELSE '1' END) AS M_CATE_YN
             ,(CASE WHEN SF_SUBSTR(#{ITEM_CLS1},1,1) = 'P' THEN '1' ELSE '0' END) AS P_CATE_YN from dual
      ) T
ON (MTGC.GATE_CD = T.GATE_CD
 AND MTGC.BUYER_CD = T.BUYER_CD
 AND MTGC.ITEM_CD = T.ITEM_CD
 AND MTGC.M_CATE_YN = T.M_CATE_YN
 AND MTGC.P_CATE_YN = T.P_CATE_YN)

WHEN MATCHED THEN UPDATE SET
      MOD_DATE = SYSDATE
     ,MOD_USER_ID = #{ses.userId}
     ,ITEM_CLS1 = #{ITEM_CLS1}
     ,ITEM_CLS2 = #{ITEM_CLS2}
     ,ITEM_CLS3 = #{ITEM_CLS3}
     ,ITEM_CLS4 = #{ITEM_CLS4}
WHEN NOT MATCHED THEN INSERT (
     GATE_CD
    ,BUYER_CD
    ,ITEM_CD
    ,M_CATE_YN
    ,P_CATE_YN
    ,ITEM_CLS1
    ,ITEM_CLS2
    ,ITEM_CLS3
    ,ITEM_CLS4
    ,REG_DATE
    ,REG_USER_ID
    ,MOD_DATE
    ,MOD_USER_ID
    ,DEL_FLAG
) VALUES (
     #{ses.gateCd}
    ,#{ses.companyCd}
    ,#{ITEM_CD}
    ,'1'
    ,'0'
    ,#{ITEM_CLS1}
    ,#{ITEM_CLS2}
    ,#{ITEM_CLS3}
    ,#{ITEM_CLS4}
    ,SYSDATE
    ,#{ses.userId}
    ,SYSDATE
    ,#{ses.userId}
    ,'0'
)

UPDATE STOUNWRQ
   SET MOD_DATE = SYSDATE
     , MOD_USER_ID = #{ses.userId}
     , ITEM_CD = #{ITEM_CD}
     , PROGRESS_CD = '400'
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{ses.companyCd}
   AND DEPT_CD  = #{ses.deptCd}
   AND ITEM_REQ_NO  = #{ITEM_REQ_NO}
   AND ITEM_REQ_SEQ = #{ITEM_REQ_SEQ}

mapper.select:
SELECT A.* FROM ( SELECT MTGL.GATE_CD , MTGL.ITEM_CD , MTGL.ITEM_DESC , MTGL.ITEM_SPEC , MTGL.MAKER_CD , GETMKBRNAME(MTGL.GATE_CD, MTGL.BUYER_CD, 'MK', MTGL.MAKER_CD) AS MAKER_NM , MTGL.MAKER_PART_NO , MTGL.BRAND_CD , GETMKBRNAME(MTGL.GATE_CD, MTGL.BUYER_CD, 'BR', MTGL.BRAND_CD) AS BRAND_NM , MTGL.ORIGIN_CD , MTGL.UNIT_CD , MTGL.VAT_CD , MTGL.DIRECT_PO_FLAG , (MTGL.MOD_DATE, 'YYYY-MM-DD HH24:MI') MOD_DATE , GETUSERNAME(MTGL.GATE_CD, MTGL.MOD_USER_ID, #{ses.langCd}) AS MOD_USER_NM , GETITEMCLASSPATH(MTGL.GATE_CD, #{ses.companyCd}, MTGL.ITEM_CD) AS ITEM_CLS_NM , MTGL.BUYER_CD , MTGL.STD_ITEM_CD , MTGC.ITEM_CLS1 , MTGC.ITEM_CLS2 , MTGC.ITEM_CLS3 , MTGC.ITEM_CLS4 FROM STOCMTGL MTGL LEFT JOIN STOCMTGC MTGC ON (MTGL.GATE_CD = MTGC.GATE_CD AND MTGL.BUYER_CD = MTGC.BUYER_CD AND MTGL.ITEM_CD = MTGC.ITEM_CD AND MTGC.DEL_FLAG = '0') WHERE MTGL.GATE_CD = #{ses.gateCd} AND MTGL.BUYER_CD = #{ses.companyCd} AND MTGL.DEL_FLAG = '0'
AND MTGC.ITEM_CLS1 = #{ITEM_CLS1}
AND MTGC.ITEM_CLS2 = #{ITEM_CLS2}
AND MTGC.ITEM_CLS3 = #{ITEM_CLS3}
AND MTGC.ITEM_CLS4 = #{ITEM_CLS4}
AND UPPER(MTGL.ITEM_CD) LIKE '%'UPPER(#{ITEM_CD})'%'
AND (${ITEM_DESC})
AND (${ITEM_SPEC})
AND UPPER(MTGL.MAKER_CD) LIKE '%'UPPER(#{MAKER_CD})'%'
AND UPPER(MTGL.MAKER_PART_NO) LIKE '%'UPPER(#{MAKER_PART_NO})'%'
AND UPPER(MTGL.BRAND_CD) LIKE '%'UPPER(#{BRAND_CD})'%'
) A WHERE 1=1
AND UPPER(A.MAKER_NM) LIKE '%'UPPER(#{MAKER_NM})'%'
AND UPPER(A.BRAND_NM) LIKE '%'UPPER(#{BRAND_NM})'%'

SELECT A.* FROM ( SELECT MTGL.GATE_CD , MTGL.BUYER_CD , MTGL.ITEM_CD , MTGL.ITEM_DESC , MTGL.ITEM_SPEC , MTGL.MAKER_CD , GETMKBRNAME(MTGL.GATE_CD, MTGL.BUYER_CD, 'MK', MTGL.MAKER_CD) AS MAKER_NM , MTGL.MAKER_PART_NO , MTGL.BRAND_CD , GETMKBRNAME(MTGL.GATE_CD, MTGL.BUYER_CD, 'BR', MTGL.BRAND_CD) AS BRAND_NM , MTGL.ORIGIN_CD , MTGL.UNIT_CD , MTGL.DIRECT_PO_FLAG , MTGL.MAJOR_ITEM_FLAG , INFO.VENDOR_CD , VNGL.VENDOR_NM AS PURCHASE_NM , INFO.CUR , INFO.UNIT_PRC AS CONT_AMT , INFO.TAX_CD AS VAT_TYPE , (MTGL.MOD_DATE, 'YYYY-MM-DD HH24:MI') MOD_DATE , GETUSERNAME(MTGL.GATE_CD, MTGL.MOD_USER_ID, #{ses.langCd}) AS MOD_USER_NM , GETITEMCLASSPATH(MTGL.GATE_CD, #{ses.companyCd}, MTGL.ITEM_CD) AS ITEM_CLS_NM , MTGL.STD_ITEM_CD , MTGC.ITEM_CLS1 , MTGC.ITEM_CLS2 , MTGC.ITEM_CLS3 , MTGC.ITEM_CLS4 FROM STOCMTGL MTGL LEFT JOIN STOCMTGC MTGC ON (MTGL.GATE_CD = MTGC.GATE_CD AND MTGL.BUYER_CD = MTGC.BUYER_CD AND MTGL.ITEM_CD = MTGC.ITEM_CD AND MTGC.DEL_FLAG = '0') LEFT JOIN STOCINFO INFO ON (INFO.GATE_CD = MTGL.GATE_CD AND INFO.PR_BUYER_CD = MTGL.BUYER_CD AND INFO.PR_DEPT_CD = #{ses.deptCd} AND INFO.ITEM_CD = MTGL.ITEM_CD AND SYSDATE BETWEEN INFO.VALID_FROM_DATE AND INFO.VALID_TO_DATE AND INFO.DEL_FLAG = '0') LEFT JOIN STOCVNGL VNGL ON (VNGL.GATE_CD = INFO.GATE_CD AND VNGL.VENDOR_CD = INFO.VENDOR_CD AND VNGL.DEL_FLAG = '0') WHERE MTGL.GATE_CD = #{ses.gateCd} AND MTGL.BUYER_CD = #{ses.companyCd} AND MTGL.DEL_FLAG = '0'
AND MTGC.ITEM_CLS1 = #{ITEM_CLS1}
AND MTGC.ITEM_CLS2 = #{ITEM_CLS2}
AND MTGC.ITEM_CLS3 = #{ITEM_CLS3}
AND MTGC.ITEM_CLS4 = #{ITEM_CLS4}
AND UPPER(MTGL.ITEM_CD) LIKE '%'UPPER(#{ITEM_CD})'%'
AND UPPER(MTGL.MAKER_PART_NO) LIKE '%'UPPER(#{MAKER_PART_NO})'%'
AND UPPER(VNGL.VENDOR_CD) LIKE '%'UPPER(#{VENDOR_CD})'%'
AND UPPER(VNGL.VENDOR_NM) LIKE '%'UPPER(#{VENDOR_NM})'%'
) A WHERE 1=1
AND ((${ITEM_DESC}) OR (${ITEM_SPEC}) )
AND UPPER(A.MAKER_NM) LIKE '%'UPPER(#{MAKER_NM})'%'

