mapper.select:
SELECT A.* FROM ( SELECT MTGL.GATE_CD , MTGL.BUYER_CD , MTGL.ITEM_CD , MTGL.ITEM_DESC , MTGL.ITEM_SPEC , MTGL.MAKER_CD , GETMKBRNAME(MTGL.GATE_CD, MTGL.BUYER_CD, 'MK', MTGL.MAKER_CD) AS MAKER_NM , MTGL.MAKER_PART_NO , MTGL.BRAND_CD , GETMKBRNAME(MTGL.GATE_CD, MTGL.BUYER_CD, 'BR', MTGL.BRAND_CD) AS BRAND_NM , MTGL.ORIGIN_CD , MTGL.UNIT_CD , MTGL.VAT_CD , (MTGL.MOD_DATE, 'YYYY-MM-DD HH24:MI') MOD_DATE , GETUSERNAME(MTGL.GATE_CD, MTGL.MOD_USER_ID, #{ses.langCd}) AS MOD_USER_NM , GETITEMCLASSPATH(MTGL.GATE_CD, #{ses.manageCd}, MTGL.ITEM_CD) AS ITEM_CLS_NM , MTGL.STD_ITEM_CD , MTGC.ITEM_CLS1 , MTGC.ITEM_CLS2 , MTGC.ITEM_CLS3 , MTGC.ITEM_CLS4 FROM STOCMTGL MTGL LEFT JOIN STOCMTGC MTGC ON (MTGL.GATE_CD = MTGC.GATE_CD AND MTGL.BUYER_CD = MTGC.BUYER_CD AND MTGL.ITEM_CD = MTGC.ITEM_CD AND MTGC.DEL_FLAG = '0') WHERE MTGL.GATE_CD = #{ses.gateCd} AND MTGL.BUYER_CD = #{ses.manageCd} AND MTGL.DEL_FLAG = '0'
AND MTGC.ITEM_CLS1 = #{ITEM_CLS1}
AND MTGC.ITEM_CLS2 = #{ITEM_CLS2}
AND MTGC.ITEM_CLS3 = #{ITEM_CLS3}
AND MTGC.ITEM_CLS4 = #{ITEM_CLS4}
AND UPPER(MTGL.ITEM_CD) LIKE '%'UPPER(#{ITEM_CD})'%'
AND (${ITEM_DESC})
AND (${ITEM_SPEC})
AND UPPER(MTGL.MAKER_PART_NO) LIKE '%'UPPER(#{MAKER_PART_NO})'%'
) A WHERE 1=1
AND UPPER(A.MAKER_NM) LIKE '%'UPPER(#{MAKER_NM})'%'
AND UPPER(A.BRAND_NM) LIKE '%'UPPER(#{BRAND_NM})'%'


		SELECT MTCR.ATTR_CD AS CODE
			 , MTCR.ATTR_NM AS CODE_NM
       		 , MTAT.ATTR_VALUE
       		 , MTCR.MDT_FLAG
       	  FROM STOCMTCR MTCR
		  JOIN STOCMTAT MTAT
		    ON(MTCR.GATE_CD   = MTAT.GATE_CD
		   AND MTCR.BUYER_CD  = MTAT.BUYER_CD
		   AND MTCR.ITEM_CLS1 = MTAT.ITEM_CLS1
		   AND MTCR.ITEM_CLS2 = MTAT.ITEM_CLS2
		   AND MTCR.ITEM_CLS3 = MTAT.ITEM_CLS3
		   AND MTCR.ITEM_CLS4 = MTAT.ITEM_CLS4
		   AND MTCR.ATTR_CD   = MTAT.ATTR_CD
		   AND MTAT.ITEM_CD   = #{ITEM_CD}
		   AND MTAT.DEL_FLAG  = '0')
         WHERE MTCR.GATE_CD   = #{ses.gateCd}
           AND MTCR.BUYER_CD  = #{BUYER_CD}
    	   AND MTCR.ITEM_CLS1 = #{ITEM_CLS1}
    	   AND MTCR.ITEM_CLS2 = #{ITEM_CLS2}
    	   AND MTCR.ITEM_CLS3 = #{ITEM_CLS3}
    	   AND MTCR.ITEM_CLS4 = #{ITEM_CLS4}
       	   AND MTCR.DEL_FLAG  = '0'
    	 ORDER BY MTCR.SORT_SQ

SELECT /*+ INDEX (STOCMKBR INDEX [STOCMKBR_GATE_CD_IDX]) */ MKBR.MKBR_TYPE , MKBR.MKBR_CD , MKBR.MKBR_NM , MKBR.USE_FLAG , MKBR.MAJOR_ITEM_TEXT , MKBR.ADD_TEXT , MKBR.REG_USER_ID AS REG_USER_ID , getUserName(#{ses.gateCd}, MKBR.REG_USER_ID, #{ses.langCd}) AS REG_USER_NM , getUserName(#{ses.gateCd}, MKBR.MOD_USER_ID, #{ses.langCd}) AS MOD_USER_NM , ( MKBR.REG_DATE , 'YYYY-MM-DD HH24:MI') AS REG_DATE , ( MKBR.MOD_DATE , 'YYYY-MM-DD HH24:MI') AS MOD_DATE , MKBR.MOD_USER_ID FROM STOCMKBR MKBR WHERE MKBR.GATE_CD = #{ses.gateCd} AND MKBR.BUYER_CD = #{ses.companyCd}
AND MKBR.MKBR_TYPE = #{MKBR_TYPE}
AND UPPER(MKBR.MKBR_NM) LIKE '%'UPPER(#{MKBR_NM})'%'
AND MKBR.USE_FLAG = #{USE_FLAG}
AND MKBR.DEL_FLAG = '0' ORDER BY MKBR.MKBR_TYPE DESC, MKBR.MKBR_CD

mapper.update:
        MERGE  STOCMKBR MKBR
        USING (SELECT #{ses.gateCd} AS GATE_CD
        			 ,#{ses.companyCd} AS BUYER_CD
                     ,#{MKBR_TYPE} AS MKBR_TYPE
                     ,#{MKBR_CD} AS MKBR_CD
	          ) DATA
	        ON (MKBR.GATE_CD   = DATA.GATE_CD
	        AND MKBR.BUYER_CD  = DATA.BUYER_CD
	        AND MKBR.MKBR_TYPE = DATA.MKBR_TYPE
	        AND MKBR.MKBR_CD   = DATA.MKBR_CD)
        WHEN MATCHED THEN
        UPDATE SET
             MKBR_NM = #{MKBR_NM}
            ,USE_FLAG = #{USE_FLAG}
            ,MAJOR_ITEM_TEXT = #{MAJOR_ITEM_TEXT}
            ,ADD_TEXT = #{ADD_TEXT}
            ,MOD_DATE = SYSDATE
            ,MOD_USER_ID = #{ses.userId}
        WHEN NOT MATCHED THEN
        INSERT (
             GATE_CD
            ,BUYER_CD
            ,MKBR_TYPE
            ,MKBR_CD
            ,REG_DATE
            ,REG_USER_ID
            ,MOD_DATE
            ,MOD_USER_ID
            ,DEL_FLAG
            ,MKBR_NM
            ,USE_FLAG
            ,MAJOR_ITEM_TEXT
            ,ADD_TEXT
        ) VALUES (
            #{ses.gateCd}
            ,#{ses.companyCd}
            ,#{MKBR_TYPE}
            ,#{MKBR_TYPE}||SEQ_STOCMKBR.nextval
            ,SYSDATE
            ,#{ses.userId}
            ,SYSDATE
            ,#{ses.userId}
            ,'0'
            ,#{MKBR_NM}
            ,#{USE_FLAG}
            ,#{MAJOR_ITEM_TEXT}
            ,#{ADD_TEXT}
        )

mapper.select:
SELECT COUNT(BUYER_CD) FROM STOCMTCA
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}

        SELECT

		       CASE WHEN #{ITEM_CLS_TYPE} = 'C2' THEN #{ITEM_CLS1}  (LPAD(TO_NUMBER(MAX(SUBSTR(ITEM_CLS2, (#{ITEM_CLS1})+1, 2)))+1, 2, '0'), '01')
                    WHEN #{ITEM_CLS_TYPE} = 'C3' THEN #{ITEM_CLS2}  (LPAD(TO_NUMBER(MAX(SUBSTR(ITEM_CLS3, (#{ITEM_CLS2})+1, 2)))+1, 2, '0'), '01')
                    WHEN #{ITEM_CLS_TYPE} = 'C4' THEN #{ITEM_CLS3}  (LPAD(TO_NUMBER(MAX(SUBSTR(ITEM_CLS4, (#{ITEM_CLS3})+1, 2)))+1, 2, '0'), '01')
                    END AS VALUE


		       CASE WHEN #{ITEM_CLS_TYPE} = 'C2' THEN #{ITEM_CLS1}  (SF_LPAD(CONVERT(INT,MAX(substring(ITEM_CLS2,len(#{ITEM_CLS1})+1, 2)))+1, 2, '0'), '01')
                    WHEN #{ITEM_CLS_TYPE} = 'C3' THEN CASE WHEN #{ITEM_CLS2} IS NULL THEN '' ELSE #{ITEM_CLS2} END  (SF_LPAD(CONVERT(INT,MAX(substring(ITEM_CLS3,len(#{ITEM_CLS2})+1, 2)))+1, 2, '0'), '01')
                    WHEN #{ITEM_CLS_TYPE} = 'C4' THEN CASE WHEN #{ITEM_CLS3} IS NULL THEN '' ELSE #{ITEM_CLS3} END  (SF_LPAD(CONVERT(INT,MAX(substring(ITEM_CLS4,len(#{ITEM_CLS3})+1, 2)))+1, 2, '0'), '01')
                    END AS VALUE

         FROM STOCMTCA
        WHERE GATE_CD = #{ses.gateCd}
          AND BUYER_CD = #{BUYER_CD}
          AND DEL_FLAG = '0'

             AND ITEM_CLS1 = #{ITEM_CLS1}
             AND ITEM_CLS2 = #{ITEM_CLS2}
             AND ITEM_CLS3 = #{ITEM_CLS3}

SELECT 
       COUNT(DEL_FLAG)
  FROM STOCMTCA
 WHERE GATE_CD= #{ses.gateCd}

   AND BUYER_CD = #{BUYER_CD}
 AND ITEM_CLS1 = #{ITEM_CLS1}
 AND ITEM_CLS2 = #{ITEM_CLS2}
 AND ITEM_CLS3 = #{ITEM_CLS3}
 AND ITEM_CLS4 = #{ITEM_CLS4}

mapper.update:
        UPDATE STOCMTCA
        SET    MOD_USER_ID          =  #{ses.userId}
             , MOD_DATE             = SYSDATE
             , ITEM_CLS_NM          = #{ITEM_CLS_NM}
             , USE_FLAG             = #{USE_FLAG}
             , DEL_FLAG             = '0'
             , ITEM_CLS             = (CASE WHEN ITEM_CLS2 = '*' THEN ITEM_CLS1
                                            ELSE (CASE WHEN ITEM_CLS3 = '*' THEN ITEM_CLS2
                                            ELSE (CASE WHEN ITEM_CLS4 = '*' THEN ITEM_CLS3 ELSE ITEM_CLS4 END) END) END)
             , UP_ITEM_CLS          = (CASE WHEN ITEM_CLS2 = '*' THEN ''
                                            ELSE (CASE WHEN ITEM_CLS3 = '*' THEN ITEM_CLS1
                                            ELSE (CASE WHEN ITEM_CLS4 = '*' THEN ITEM_CLS2 ELSE ITEM_CLS3 END) END) END)
			 , SORT_SQ 				= #{SORT_SQ}
         WHERE GATE_CD = #{ses.gateCd}
           AND BUYER_CD = #{BUYER_CD}
         AND ITEM_CLS1 = #{ITEM_CLS1}
         AND ITEM_CLS2 = #{ITEM_CLS2}
         AND ITEM_CLS3 = #{ITEM_CLS3}
         AND ITEM_CLS4 = #{ITEM_CLS4}

mapper.select:
    	SELECT (SELECT COUNT(GATE_CD)
                  FROM STOCMTCA
                 WHERE GATE_CD  = #{ses.gateCd}
                   AND BUYER_CD = #{BUYER_CD}
                   AND DEL_FLAG = '0'
				 AND ITEM_CLS1 = #{ITEM_CLS1}
				 AND ITEM_CLS2 = #{ITEM_CLS2}
				 AND ITEM_CLS3 = #{ITEM_CLS3}
				 AND ITEM_CLS4 = #{ITEM_CLS4}
    	       ) +
    	       (SELECT COUNT(GATE_CD)
                  FROM STOCMTGC
                 WHERE GATE_CD  = #{ses.gateCd}
                   AND BUYER_CD = #{BUYER_CD}
                   AND DEL_FLAG = '0'
				 AND ITEM_CLS1 = #{ITEM_CLS1}
				 AND ITEM_CLS2 = #{ITEM_CLS2}
				 AND ITEM_CLS3 = #{ITEM_CLS3}
				 AND ITEM_CLS4 = #{ITEM_CLS4}
    	       ) as CNT

mapper.insert:
INSERT INTO STOCMTCA (
       GATE_CD
     , BUYER_CD
     , ITEM_CLS1
     , ITEM_CLS2
     , ITEM_CLS3
     , ITEM_CLS4
     , REG_DATE
     , REG_USER_ID
     , MOD_DATE
     , MOD_USER_ID
     , DEL_FLAG
     , USE_FLAG
     , ITEM_CLS_NM
     , ITEM_CLS_TYPE
     , SORT_SQ
     , ITEM_CLS
     , UP_ITEM_CLS
)
VALUES  (#{ses.gateCd}
     , #{BUYER_CD}
     , #{ITEM_CLS1}
     , #{ITEM_CLS2}
     , #{ITEM_CLS3}
     , #{ITEM_CLS4}
     , SYSDATE
     ,  #{ses.userId}
     , SYSDATE
     ,  #{ses.userId}
     , '0'
     , #{USE_FLAG}
     , #{ITEM_CLS_NM}
     , #{ITEM_CLS_TYPE}
     , #{SORT_SQ}
     ,(CASE WHEN #{ITEM_CLS2} = '*' THEN #{ITEM_CLS1}
            ELSE (CASE WHEN #{ITEM_CLS3} = '*' THEN #{ITEM_CLS2}
            ELSE (CASE WHEN #{ITEM_CLS4} = '*' THEN #{ITEM_CLS3} ELSE #{ITEM_CLS4} END) END) END)
     ,(CASE WHEN #{ITEM_CLS2} = '*' THEN ''
            ELSE (CASE WHEN #{ITEM_CLS3} = '*' THEN #{ITEM_CLS1}
            ELSE (CASE WHEN #{ITEM_CLS4} = '*' THEN #{ITEM_CLS2} ELSE #{ITEM_CLS3} END) END) END)
)

mapper.delete:
